using EnergyModel

module Electric_CER_Exogenous_Units

import ...EnergyModel: ReadDisk,WriteDisk,Select,Zero
import ...EnergyModel: HisTime,ITime,MaxTime,First,Future,Final,Yr
import ...EnergyModel: @finite_math,finite_inverse,finite_divide,finite_power,finite_exp,finite_log
import ...EnergyModel: DB

const VariableArray{N} = Array{Float32,N} where {N}
const SetArray = Vector{String}

Base.@kwdef struct EControl
  db::String

  Area::SetArray = ReadDisk(db,"MainDB/AreaKey")
  FuelEP::SetArray = ReadDisk(db,"MainDB/FuelEPKey")
  FuelEPDS::SetArray = ReadDisk(db,"MainDB/FuelEPDS")
  FuelEPs::Vector{Int} = collect(Select(FuelEP))
  Month::SetArray = ReadDisk(db,"MainDB/MonthKey")
  Months::Vector{Int} = collect(Select(Month))    
  Plant::SetArray = ReadDisk(db,"MainDB/PlantKey")
  PlantDS::SetArray = ReadDisk(db,"MainDB/PlantDS")
  Plants::Vector{Int} = collect(Select(Plant))
  Poll::SetArray = ReadDisk(db,"MainDB/PollKey")
  PollDS::SetArray = ReadDisk(db,"MainDB/PollDS")
  Polls::Vector{Int} = collect(Select(Poll))
  TimeP::SetArray = ReadDisk(db,"MainDB/TimePKey")
  TimePs::Vector{Int} = collect(Select(TimeP))    
  Unit::SetArray = ReadDisk(db,"MainDB/UnitKey")
  Units::Vector{Int} = collect(Select(Unit))
  Year::SetArray = ReadDisk(db,"MainDB/YearKey")
  YearDS::SetArray = ReadDisk(db,"MainDB/YearDS")
  Years::Vector{Int} = collect(Select(Year))
  
  UnArea::Array{String} = ReadDisk(db,"EGInput/UnArea") # [Unit] Area Pointer
  UnCode::Array{String} = ReadDisk(db,"EGInput/UnCode") # [Unit] Unit Code
  UnCogen::VariableArray{1} = ReadDisk(db,"EGInput/UnCogen") # [Unit] Industrial Self-Generation Flag (1=Self-Generation)
  UnFlFrMax::VariableArray{3} = ReadDisk(db,"EGInput/UnFlFrMax") # [Unit,FuelEP,Year] Fuel Fraction Maximum
  UnFlFrMin::VariableArray{3} = ReadDisk(db,"EGInput/UnFlFrMin") # [Unit,FuelEP,Year] Fuel Fraction Minimum
  UnLimited::VariableArray{2} = ReadDisk(db,"EGInput/UnLimited") #[Unit,Year]  Limited Energy Units Switch (Switch) (1=Limited Energy Unit)  
  UnNation::Array{String} = ReadDisk(db,"EGInput/UnNation") # [Unit] Nation
  UnOnLine::VariableArray{1} = ReadDisk(db,"EGInput/UnOnLine") # [Unit] On-Line Date (Year)
  UnOR::VariableArray{4} = ReadDisk(db,"EGInput/UnOR") # [Unit,TimeP,Month,Year] Outage Rate (MW/MW)
  UnOUREG::VariableArray{2} = ReadDisk(db,"EGInput/UnOUREG") # [Unit,Year] Own Use Rate for Generation (GWh/GWh)
  UnOURGC::VariableArray{2} = ReadDisk(db,"EGInput/UnOURGC") # [Unit,Year] Own Use Rate for Generating Capacity (MW/MW)
  UnPCFMax::VariableArray{2} = ReadDisk(db,"EGInput/UnPCFMax") #[Unit,Year]  Unit Capacity Factor (MW/MW)
  UnPlant::Array{String} = ReadDisk(db,"EGInput/UnPlant") # [Unit] Plant Type
  UnPSoMaxGridFraction::VariableArray{2} = ReadDisk(db,"EGInput/UnPSoMaxGridFraction") # [Unit,Year]  Maximum Fraction Sold to Grid (GWh/GWh)
  UnRetire::VariableArray{2} = ReadDisk(db,"EGInput/UnRetire") # [Unit,Year] Retirement Date (Year)
  UnSector::Array{String} = ReadDisk(db,"EGInput/UnSector") # [Unit] Unit Sector
  UnSqFr::VariableArray{3} = ReadDisk(db,"EGInput/UnSqFr") # [Unit,Poll,Year] Sequestered Pollution Fraction (Tonnes/Tonnes)
  xUnGCCI::VariableArray{2} = ReadDisk(db,"EGInput/xUnGCCI") # [Unit,Year] Generating Capacity Initiated (MW)
  xUnGCCR::VariableArray{2} = ReadDisk(db,"EGInput/xUnGCCR") # [Unit,Year] Exogenous Generating Capacity Completion Rate (MW)
end

function ElecPolicy(db)
  data = EControl(; db)
  (; FuelEP,FuelEPs,Months,Poll,TimePs,Units,Years) = data
  (; UnCode,UnCogen,UnFlFrMax,UnFlFrMin,UnOnLine,UnOR,UnOUREG,UnOURGC,UnPCFMax,UnLimited) = data
  (; UnPSoMaxGridFraction,UnRetire,UnSqFr,xUnGCCI,xUnGCCR) = data
  
  ######################
  # NEXTGRID DECISIONS #
  ######################
  
  # NextGrid can make 5 different decisions to enforce the CER:
  # 0) Manage units not covered by NextGrid
  # 1) Retirement
  # 2) CCS
  # 3) Limitation
  # 4) Fuel blending
  # 5) Defection
  # 
  # For unit with UnOnLine<2010, CER is applied in 2035
  # For unit with UnOnLine>2015, CER is applied in 2035
  # For unit with 2010<=UnOnLine<=2015, CER is applied in UnOnLine+25
  
  ##########################
  # 1) RETIRE POWER PLANTS #
  ##########################
  
  # Plant Retirement Method: Update UnRetire
  # Note: In a previous version (CG1), NextGrid could retire a fraction of the capacity and use the rest normally
  # It is now assumed that 100% of the capacity is removed when the plant is retired (thus only UnRetire is udpated)
  #
  # A) Retire in 2035 utility-emitting>25MW units not handled by NextGrid
  # (or after, based on their UnOnLine)
  # 
  #  for unit in Units
  #    if (UnCode[unit] == "BC_FORTNELSON") || (UnCode[unit] == "NS_FastActinGen") ||
  #       (UnCode[unit] == "NS00008000101") || (UnCode[unit] == "NS00008000102") ||
  #       (UnCode[unit] == "NS00008000103") || (UnCode[unit] == "NS00008000104") ||
  #       (UnCode[unit] == "NS00008000201") || (UnCode[unit] == "NS00008000301") ||
  #       (UnCode[unit] == "NS00008000302") || (UnCode[unit] == "NS00008004201") ||
  #       (UnCode[unit] == "NS00008004202") || (UnCode[unit] == "NS00008004203") ||
  #       (UnCode[unit] == "ON_DOWCHEMICAL") || (UnCode[unit] == "ON_DPNTMTLND") ||
  #       (UnCode[unit] == "ON_KAPGS") || (UnCode[unit] == "ON_North_Bay") ||
  #       (UnCode[unit] == "ON_TAOHSC") || (UnCode[unit] == "ON00027100101") ||
  #       (UnCode[unit] == "PE00012400102") || (UnCode[unit] == "SK00015301403")
  #      UnRetire[unit,year] = 2035
  #    end
  #  end
  # 
  # B) Retire power plants according to NextGrid decisions
  #

  for unit in Units

    if UnCode[unit] == "AB00001200101"
      for year in Years
        UnRetire[unit,year] =2035
      end
    end

    if UnCode[unit] == "AB00001200102"
      for year in Years
        UnRetire[unit,year] =2035
      end
    end

    if UnCode[unit] == "AB00001300203NG"
      for year in Years
        UnRetire[unit,year] =2038
      end
    end

    if UnCode[unit] == "AB00002201502NG"
      for year in Years
        UnRetire[unit,year] =2038
      end
    end

    if UnCode[unit] == "AB00002201606NG"
      for year in Years
        UnRetire[unit,year] =2025
      end
    end

    if UnCode[unit] == "AB00029600603NG"
      for year in Years
        UnRetire[unit,year] =2025
      end
    end

    if UnCode[unit] == "AB00029600801NG"
      for year in Years
        UnRetire[unit,year] =2025
      end
    end

    if UnCode[unit] == "AB00029600802NG"
      for year in Years
        UnRetire[unit,year] =2038
      end
    end

    if UnCode[unit] == "AB00035000101"
      for year in Years
        UnRetire[unit,year] =2035
      end
    end

    if UnCode[unit] == "AB00035000102"
      for year in Years
        UnRetire[unit,year] =2035
      end
    end

    if UnCode[unit] == "AB00035500101"
      for year in Years
        UnRetire[unit,year] =2035
      end
    end

    if UnCode[unit] == "AB_KaybobS3_Cg"
      for year in Years
        UnRetire[unit,year] =2035
      end
    end

    if UnCode[unit] == "AB_New_26NG"
      for year in Years
        UnRetire[unit,year] =2038
      end
    end

    if UnCode[unit] == "NB00038900100"
      for year in Years
        UnRetire[unit,year] =2048
      end
    end

    if UnCode[unit] == "NS00008000101"
      for year in Years
        UnRetire[unit,year] =2050
      end
    end

    if UnCode[unit] == "NS00008000102"
      for year in Years
        UnRetire[unit,year] =2050
      end
    end

    if UnCode[unit] == "NS00008000103"
      for year in Years
        UnRetire[unit,year] =2050
      end
    end

    if UnCode[unit] == "NS00008000104"
      for year in Years
        UnRetire[unit,year] =2050
      end
    end

    if UnCode[unit] == "NS00008000301"
      for year in Years
        UnRetire[unit,year] =2050
      end
    end

    if UnCode[unit] == "NS00008000302"
      for year in Years
        UnRetire[unit,year] =2050
      end
    end

    if UnCode[unit] == "NS00008004201"
      for year in Years
        UnRetire[unit,year] =2035
      end
    end

    if UnCode[unit] == "NS00008004202"
      for year in Years
        UnRetire[unit,year] =2035
      end
    end

    if UnCode[unit] == "NS00008004203"
      for year in Years
        UnRetire[unit,year] =2035
      end
    end

    if UnCode[unit] == "NS00026100101"
      for year in Years
        UnRetire[unit,year] =2035
      end
    end

    if UnCode[unit] == "NS_FastActinGen"
      for year in Years
        UnRetire[unit,year] =2050
      end
    end

    if UnCode[unit] == "QC00029400101"
      for year in Years
        UnRetire[unit,year] =2035
      end
    end

    if UnCode[unit] == "SK00015301402"
      for year in Years
        UnRetire[unit,year] =2035
      end
    end

    if UnCode[unit] == "SK00015301804"
      for year in Years
        UnRetire[unit,year] =2041
      end
    end

  end


  
  ##########
  # 2) CCS #
  ##########
  #  
  # Method: a new plant must be created because CCS is a different plant type and UnPlant cannot be changed.
  #
  # A) Activate the converted CCS plants in UnitCreate_ForPolicies.txt
  #    Note: for the following reasons, it is not possible to use the generic utility CCS policy plant:
  #      1) some converted plants are non-utility cogen plants
  #      2) each CCS of a region may behave differently (different fuels, different capture mode: CCS on/off over time)
  #    
  #    IMPORTANT: The python script automatically update UnitCreate_ForPolicies.txt
  #               but the file must be copied in model files every time it has been updated.
  #
  #
  # B) Remove the original non-ccs power plant (Update UnRetire)
  #

  for unit in Units

    if UnCode[unit] == "AB00002000101"
      for year in Years
        UnRetire[unit,year] = 2050
      end
    end

    if UnCode[unit] == "AB00029600101"
      for year in Years
        UnRetire[unit,year] = 2050
      end
    end

    if UnCode[unit] == "AB00034100200"
      for year in Years
        UnRetire[unit,year] = 2050
      end
    end

    if UnCode[unit] == "AB00041700201"
      for year in Years
        UnRetire[unit,year] = 2050
      end
    end

    if UnCode[unit] == "AB_CL_NG_2"
      for year in Years
        UnRetire[unit,year] = 2050
      end
    end

    if UnCode[unit] == "AB_CSS002000"
      for year in Years
        UnRetire[unit,year] = 2050
      end
    end

    if UnCode[unit] == "AB_LongLake_NG"
      for year in Years
        UnRetire[unit,year] = 2050
      end
    end

    if UnCode[unit] == "AB_New_17"
      for year in Years
        UnRetire[unit,year] = 2050
      end
    end

    if UnCode[unit] == "AB_Scoria_Cg"
      for year in Years
        UnRetire[unit,year] = 2050
      end
    end

    if UnCode[unit] == "AB_Shell_Carol"
      for year in Years
        UnRetire[unit,year] = 2050
      end
    end

    if UnCode[unit] == "SK00015200201"
      for year in Years
        UnRetire[unit,year] = 2050
      end
    end

    if UnCode[unit] == "SK00015200202"
      for year in Years
        UnRetire[unit,year] = 2050
      end
    end

    if UnCode[unit] == "SK00038800100"
      for year in Years
        UnRetire[unit,year] = 2050
      end
    end

  end


  # 
  # C) Add capacity to the new CCS plants
  # 
  # Increase xUnGCCI the first time the capacity is increased,
  # then increase capacity with xUnGCCR (incremental capacity)

  for unit in Units 

    if UnCode[unit] == "AB_OILS0_CCS"
      UnOnLine[unit] = min(UnOnLine[unit],Yr(2050))
      xUnGCCI[unit,Yr(2048)] = 50.0
    end

    if UnCode[unit] == "AB_CSSO1_CCS"
      UnOnLine[unit] = min(UnOnLine[unit],Yr(2050))
      xUnGCCI[unit,Yr(2048)] = 105.934
    end

    if UnCode[unit] == "AB_PETR2_CCS"
      UnOnLine[unit] = min(UnOnLine[unit],Yr(2050))
      xUnGCCI[unit,Yr(2048)] = 60.76272994
    end

    if UnCode[unit] == "AB_SAGD3_CCS"
      UnOnLine[unit] = min(UnOnLine[unit],Yr(2050))
      xUnGCCI[unit,Yr(2048)] = 207.0
    end

    if UnCode[unit] == "AB_SAGD4_CCS"
      UnOnLine[unit] = min(UnOnLine[unit],Yr(2050))
      xUnGCCI[unit,Yr(2048)] = 101.0
    end

    if UnCode[unit] == "AB_CSSO5_CCS"
      UnOnLine[unit] = min(UnOnLine[unit],Yr(2050))
      xUnGCCI[unit,Yr(2048)] = 200.71800000000002
    end

    if UnCode[unit] == "AB_SAGD6_CCS"
      UnOnLine[unit] = min(UnOnLine[unit],Yr(2050))
      xUnGCCI[unit,Yr(2048)] = 220.0
    end

    if UnCode[unit] == "AB_SAGD7_CCS"
      UnOnLine[unit] = min(UnOnLine[unit],Yr(2050))
      xUnGCCI[unit,Yr(2048)] = 101.0
    end

    if UnCode[unit] == "AB_PETR8_CCS"
      UnOnLine[unit] = min(UnOnLine[unit],Yr(2050))
      xUnGCCI[unit,Yr(2048)] = 61.269000000000005
    end

    if UnCode[unit] == "AB_INDU9_CCS"
      UnOnLine[unit] = min(UnOnLine[unit],Yr(2050))
      xUnGCCI[unit,Yr(2048)] = 62.387
    end

    if UnCode[unit] == "SK_NONM10_CCS"
      UnOnLine[unit] = min(UnOnLine[unit],Yr(2050))
      xUnGCCI[unit,Yr(2048)] = 28.0
    end

    if UnCode[unit] == "SK_NONM11_CCS"
      UnOnLine[unit] = min(UnOnLine[unit],Yr(2050))
      xUnGCCI[unit,Yr(2048)] = 27.0
    end

    if UnCode[unit] == "SK_NONM12_CCS"
      UnOnLine[unit] = min(UnOnLine[unit],Yr(2050))
      xUnGCCI[unit,Yr(2048)] = 234.0
    end

    # It is AB_Black_Bear, it's already there
    #if UnCode[unit] == "AB_UTIL13_CCS"
    #  UnOnLine[unit] = min(UnOnLine[unit],Yr(2050))
    #  xUnGCCI[unit,Yr(2048)] = 450.0
    #end

  end
  
  # 
  # D) NGCCS can intermittently capture CO2
  #
  
  CO2 = Select(Poll,"CO2")

  for unit in Units

    if UnCode[unit] == "AB_OILS0_CCS"
      years = collect(Yr(2050):Yr(2050))
      for year in years
        UnSqFr[unit,CO2,year] = 0.754
        UnOUREG[unit,year] = 0.1357
        UnOURGC[unit,year] = 0.1357
      end
    end

    if UnCode[unit] == "AB_CSSO1_CCS"
      years = collect(Yr(2050):Yr(2050))
      for year in years
        UnSqFr[unit,CO2,year] = 0.95
        UnOUREG[unit,year] = 0.171
        UnOURGC[unit,year] = 0.171
      end
    end

    if UnCode[unit] == "AB_PETR2_CCS"
      years = collect(Yr(2050):Yr(2050))
      for year in years
        UnSqFr[unit,CO2,year] = 0.95
        UnOUREG[unit,year] = 0.171
        UnOURGC[unit,year] = 0.171
      end
    end

    if UnCode[unit] == "AB_SAGD3_CCS"
      years = collect(Yr(2050):Yr(2050))
      for year in years
        UnSqFr[unit,CO2,year] = 0.9476
        UnOUREG[unit,year] = 0.1706
        UnOURGC[unit,year] = 0.1706
      end
    end

    if UnCode[unit] == "AB_Black_Bear"
      years = collect(Yr(2035):Yr(2039))
      for year in years
        UnSqFr[unit,CO2,year] = 0.95
        UnOUREG[unit,year] = 0.171
        UnOURGC[unit,year] = 0.171
      end
      years = collect(Yr(2040):Yr(2044))
      for year in years
        UnSqFr[unit,CO2,year] = 0.2141
        UnOUREG[unit,year] = 0.0385
        UnOURGC[unit,year] = 0.0385
      end
      years = collect(Yr(2045):Yr(2049))
      for year in years
        UnSqFr[unit,CO2,year] = 0.2141
        UnOUREG[unit,year] = 0.0385
        UnOURGC[unit,year] = 0.0385
      end
      years = collect(Yr(2050):Yr(2050))
      for year in years
        UnSqFr[unit,CO2,year] = 0.95
        UnOUREG[unit,year] = 0.171
        UnOURGC[unit,year] = 0.171
      end
    end

    if UnCode[unit] == "AB_SAGD4_CCS"
      years = collect(Yr(2050):Yr(2050))
      for year in years
        UnSqFr[unit,CO2,year] = 0.9476
        UnOUREG[unit,year] = 0.1706
        UnOURGC[unit,year] = 0.1706
      end
    end

    if UnCode[unit] == "AB_CSSO5_CCS"
      years = collect(Yr(2050):Yr(2050))
      for year in years
        UnSqFr[unit,CO2,year] = 0.95
        UnOUREG[unit,year] = 0.171
        UnOURGC[unit,year] = 0.171
      end
    end

    if UnCode[unit] == "AB_SAGD6_CCS"
      years = collect(Yr(2050):Yr(2050))
      for year in years
        UnSqFr[unit,CO2,year] = 0.9476
        UnOUREG[unit,year] = 0.1706
        UnOURGC[unit,year] = 0.1706
      end
    end

    if UnCode[unit] == "AB_SAGD7_CCS"
      years = collect(Yr(2050):Yr(2050))
      for year in years
        UnSqFr[unit,CO2,year] = 0.9476
        UnOUREG[unit,year] = 0.1706
        UnOURGC[unit,year] = 0.1706
      end
    end

    if UnCode[unit] == "AB_PETR8_CCS"
      years = collect(Yr(2050):Yr(2050))
      for year in years
        UnSqFr[unit,CO2,year] = 0.95
        UnOUREG[unit,year] = 0.171
        UnOURGC[unit,year] = 0.171
      end
    end

    if UnCode[unit] == "AB_INDU9_CCS"
      years = collect(Yr(2050):Yr(2050))
      for year in years
        UnSqFr[unit,CO2,year] = 0.95
        UnOUREG[unit,year] = 0.171
