  #################
  # 3) Limitation #
  #################
  #
  # Method: Limiting emission is achieved by limiting generation:
  #  - using UnPCFMax for utility plants
  #  - using UnOR for non-utility (UnPCFMax does not work for non-utility plants). 
  #   
  # 3 A) Capacity factors for power plants without NextGrid decision
  # 
  # Note 1 (TD nov 2024 for AM scenario): 
  # Cogen plants are constrained only if their UnSector have PSOECC > 0 after 2035
  # Low emitting plants are not constrained (biomass, ccs)
  #
  # Note 2: in promula, capacity factors had to be reset before implementing the desired value.
  #         Maybe it is not required in julia.
  #
  
  # Utility
  # OGCT
  unit21 = Select(UnCode, ==("AB_Opal_Gas"))
  unit30 = Select(UnCode, ==("LB00007500101"))
  unit34 = Select(UnCode, ==("SK_Ermine_003"))
  unit37 = Select(UnCode, ==("SK_Yellowhead_4"))
  unit38 = Select(UnCode, ==("SK06100000030"))
  units = union(unit21, unit30, unit34, unit37, unit38)
  
  years = collect(Yr(2035):Yr(2050))
  for unit in units, year in years
    UnLimited[unit, year] = 1.0
  end
   years = collect(Yr(2035):Yr(2049))
  for unit in units, year in years
    UnPCFMax[unit,year] = 0.11
  end
   years = Yr(2050)
  for unit in units, year in years
    UnPCFMax[unit,year] = 0.07
  end
  
  
  # Industrial (UnCogen=1)
  
  # Low emission (biogenic fuel fraction <86%)
  unit1 = Select(UnCode, ==("AB_Daishowa_Cg"))
  unit2 = Select(UnCode, ==("AB00001700102"))
  unit3 = Select(UnCode, ==("AB00002300102"))
  unit4 = Select(UnCode, ==("AB00037200101"))
  unit5 = Select(UnCode, ==("AB00037200102"))
  low = union(unit1, unit2, unit3, unit4, unit5)
  # OGCC
  unit6 = Select(UnCode, ==("AB_CSS002003"))
  unit7 = Select(UnCode, ==("AB_Edmonton_NZ"))
  unit8 = Select(UnCode, ==("AB_Inglis1_Cg"))
  unit9 = Select(UnCode, ==("AB_Inglis2_Cg"))
  unit10 = Select(UnCode, ==("AB00002000300"))
  unit11 = Select(UnCode, ==("AB00034600200"))
  unit12 = Select(UnCode, ==("AB00034700200"))
  unit13 = Select(UnCode, ==("ON_GTAA_NG"))
  unit14 = Select(UnCode, ==("ON_TAOHSC"))
